function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: Map<number, { to: number; start: number; end: number }[]> = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u)!.push({ to: v, start: s, end: e });
    }

    // Dijkstra's algorithm to find the minimum time to reach node n-1
    const dist: Map<number, number> = new Map();
    dist.set(0, 0); // Starting at node 0 at time 0

    const pq: [number, number][] = [[0, 0]]; // [time, node]

    while (pq.length > 0) {
        const [time, node] = pq.shift()!;
        if (node === n - 1) {
            return time;
        }

        // Check if we have a better time for this node
        if (dist.has(node) && dist.get(node)! < time) {
            continue;
        }

        // Explore neighbors
        if (adj.has(node)) {
            for (const { to, start, end } of adj.get(node)!) {
                // Check if the edge is available at the current time
                if (time >= start && time <= end) {
                    // We can take this edge immediately
                    const newTime = time + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                } else {
                    // Find the earliest time we can take this edge
                    const earliestTime = Math.max(start, time + 1);
                    if (earliestTime <= end) {
                        const newTime = earliestTime;
                        if (!dist.has(to) || newTime < dist.get(to)!) {
                            dist.set(to, newTime);
                            pq.push([newTime, to]);
                        }
                    }
                }
            }
        }
    }

    // If we couldn't reach node n-1
    return -1;
}

